module top_module(Clock, Resetn, w, z);input Clock, Resetn, w; 
  output z; 
  reg [1:0] obf_y, Y; 
  parameter [1:0] A = 2'b00, B = 2'b01, C = 2'b10; 


  always @(w or obf_y) 
    case (obf_y) 
      A:  if (w)    Y = B; 
        else    Y = A; 
      B:  if (w)    Y = C; 
        else    Y = A; 
      C:  if (w)    Y = C; 
        else    Y = A; 
      default:      Y = 2'b00; 
    endcase 


  always @(posedge Clock) 
    if (Resetn == 1'b0) obf_y <= A; 
    else obf_y <= Y; 


  assign z = (obf_y == C); 

endmodule
